sqlMap.insert:
UPDATE pm_presales_lend_info_from_oa plio INNER JOIN pm_presales_project_header psh ON plio.lendInfoId = psh.lendInfoId
SET psh.projectCode = COALESCE(plio.projectCode, pls.projectCode, pps.projectCode, plio.processOrderNum, psh.projectCode) , psh.projectName = COALESCE(pls.projectName, pps.projectName, plio.projectName, psh.projectName) , psh.marketName = COALESCE(pls.marketName, pps.marketName, plio.marketName, psh.marketName) , psh.systemName = COALESCE(pls.systemName, pps.systemName, plio.systemName, psh.systemName) , psh.expendName = COALESCE(pls.expendName, pps.expendName, plio.expendName, psh.expendName) , psh.industryName = COALESCE(pls.industryName, pps.industryName, plio.industryName, psh.industryName) , psh.salesman = COALESCE(pls.salesManName, pps.salesManName, CONCAT_WS('-', plio.salesUserCode, plio.salesUserName), psh.salesman) , psh.salesmanLink = COALESCE(pls.salesManLink, pps.salesManLink, plio.salesUserMobile, psh.salesmanLink) , psh.productManager = COALESCE(pls.productManager, psh.productManager) , psh.lendfiles = CONCAT_WS(",", plio.infoFile, plio.provideAuthFile, plio.resaleCertificateFile) , psh.customInfo = JSON_MERGE_PATCH(IFNULL(psh.customInfo, '{}'), ) , psh.hasTransfer = IF(plio.resellSuccessfully = '是', 1, IFNULL(psh.hasTransfer, 0)) WHERE psh.customInfo ->> '$$.authDate' IS NULL;
INSERT INTO pm_presales_project_header (projectCode, projectName , marketName, systemName, expendName, industryName, officeCode , salesman, salesmanLink, productManager , lendInfoId, lendfiles, effectiveFrom, applyBy, applyTime , projectType, customInfo, source) SELECT COALESCE(plio.projectCode, pls.projectCode, pps.projectCode, plio.processOrderNum) AS projectCode , COALESCE(pls.projectName, pps.projectName, plio.projectName) AS projectName , COALESCE(pls.marketName, pps.marketName, plio.marketName) AS marketName , COALESCE(pls.systemName, pps.systemName, plio.systemName) AS systemName , COALESCE(pls.expendName, pps.expendName, plio.expendName) AS expendName , COALESCE(pls.industryName, pps.industryName, plio.industryName) AS industryName , COALESCE(pls.officeCode, pps.officeCode, plio.applyDeptCode) AS officeCode , COALESCE(pls.salesManName, pps.salesManName, CONCAT_WS('-', plio.salesUserCode, plio.salesUserName)) AS salesman , COALESCE(pls.salesManLink, pps.salesManLink, plio.salesUserMobile) AS salesmanLink , pls.productManager AS productManager, plio.lendInfoId , CONCAT_WS(",", plio.infoFile, plio.provideAuthFile, plio.resaleCertificateFile) AS lendfiles , plio.processStartTime AS effectiveFrom , plio.applyUserCode AS applyBy, plio.applyDate AS applyTime , 'oaTempAuthInfo' AS projectType , JSON_MERGE_PATCH() AS customInfo , 'OA' AS source FROM pm_presales_lend_info_from_oa plio LEFT JOIN pm_presales_project_header psh ON plio.lendInfoId = psh.lendInfoId
WHERE psh.lendInfoId IS NULL ;
